What does this program print?

```cpp
#include <iostream>
#include <sstream>
int main() {
    std::ostringstream oss;
    oss << "x=" << 5;
    std::string s = oss.str();
    oss << "+";
    std::cout << s << "\n";
    std::cout << oss.str() << "\n";
}
```

